var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그대들의 주인은 오직 고통 받는 이들일지니, 비통한 목소리를 대신하여 이 영광된 의식을 거행한다.","JPN":"そなたたちの主は苦しみに満ちた者たちのみ。悲痛な声に代わり、この栄光なる儀式を執り行おう。","ENG":"You serve no one but the afflicted. I hereby officiate this honorable ceremony on behalf of everyone who's suffering.","TWN":"你們的主人是那些受苦的人，我在此代替那些哀痛的聲音，舉行這榮耀的儀式。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"성좌의 광명을 따르며 만인을 지키기로 맹세할 자, 누구인가?","JPN":"星座の光明に従い、万人を守ると誓う者は誰だ。","ENG":"Who pledges today to follow the radiance of the constellations and protect humanity?","TWN":"跟從星座之光，宣示要守護萬民的人，是誰？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"에스테로사, 정의로운 별의 인도로 이 자리에 섰습니다.","JPN":"エステロサ、正義なる星の導きよりこの場に辿り着きました。","ENG":"I, Esterosa, stand here under the guidance of the righteous Stars.","TWN":"我 艾斯特洛索，跟從正義之星的引導站立在這位置上。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그대는 그대의 주인에게 무엇을 맹세하겠는가?","JPN":"そなたはそなたの主に何を誓うか。","ENG":"What do you pledge to your masters today?","TWN":"你要對你的主人宣示什麼誓詞？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"적막한 밤의 평화. 별처럼 빛나는 희망. 그리고 내일 새벽이 오리라는 믿음을 맹세합니다.","JPN":"寂寞たる夜の平和。星のごとく光る希望。そして次の夜明けが訪れると信じる心を誓います。","ENG":"The peace of a quiet night. Hope that shines like the stars. And the promise of a new dawn.","TWN":"我宣示，寂靜的夜晚中有和平，希望如星閃耀，以及黎明必將到來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"저……. 저 계집애, 방금 뭐라고 한 거야?","JPN":"あ……あの女、今なんてこと言ったんだ？","ENG":"That... That brat. What did she just say?","TWN":"那……那個丫頭說什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"참아. 아직 예식이 끝나지 않았어.","JPN":"落ち着け。まだ儀式の途中だぞ。","ENG":"Easy. The ceremony isn't over yet.","TWN":"再忍一下，儀式還沒結束。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"자네야말로 무슨 소리야? 저걸 듣고 가만히 있으려면 뭐하러 기사단에 들어온 건데?","JPN":"君もだぞ？　あれを聞いて落ち着けと言うのか？　君は騎士団に入った理由を忘れたのか？","ENG":"Are you serious? I didn't join the Knights to put up with that kind of crap.","TWN":"你在說什麼？聽到那種話你還能裝作沒事，那幹嘛要進騎士團？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"예식을 주관하시는 분은 무슨 잘못인가. 곧 기회가 올 거야.","JPN":"式の主催側に失礼だろう。もうすぐチャンスが来るさ。","ENG":"Don't blame the officiator. We'll have our opportunity soon enough.","TWN":"主持儀式的人何罪之有？很快就會有機會的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"칫……!","JPN":"チッ……！","ENG":"Bah...!","TWN":"嗟……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"우와, 평소에 얼굴 보기 힘들던 평기사 아저씨들이 전부 모였네.","JPN":"わあ、普段なかなか顔も見られない平騎士のおじさんたちも勢ぞろいだね。","ENG":"Whoa, all the knight bachelors are here. This is so rare.","TWN":"哇，平時很難見到的平民騎士大叔們都齊聚一堂欸！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"물론이죠, 리브 경.","JPN":"そんなこと当たり前でしょう、リブ卿。","ENG":"It is, Dame Liv.","TWN":"那當然囉，莉芙卿。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"새로운 기사단장의 취임식입니다. 기사단의 일원이라면 자신이 갑옷을 입고 있을 때 꼭 참석할 수 있길 바라마지 않을 자리죠.","JPN":"新しい騎士団長の就任式なのです。騎士団の一員なら、鎧を着ている間には参加したいと願ってやまない行事ですからね。","ENG":"Their new captain is being sworn in today. Of course, every member of the Knights wants to be here. While they still get to wear their armor, that is.","TWN":"這可是新任騎士團團長的就任儀式，只要是身為騎士團的一員，都巴不得自己還穿著鎧甲的時候，能有機會參與呢！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 다들 기뻐해야 하는 거 아냐?","JPN":"じゃあ喜ばしいことじゃないの？","ENG":"Then, shouldn't they all be happy?","TWN":"那大家不是應該要開心嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"차기 단장을 저렇게 죽일 듯이 노려보고 있으니까 살벌하다구.","JPN":"みんな次期団長を殺気が満ちた目で睨んでて、殺伐としてるよ。","ENG":"Why are they glaring daggers at their new captain like that?","TWN":"怎麼會眼神像是恨不得要殺掉新任團長似的，充滿肅殺之氣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"충분히 이해할 수 있는 반응입니다.","JPN":"それは十分理解できます。","ENG":"It's understandable.","TWN":"他們的反應也是完全可以理解的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"열두 가문의 혈통이 한 방울도 섞이지 않은 자가 두 차례나 연달아 버고 소드의 선택을 받았으니까요.","JPN":"2回連続、12家門の血を一滴も引いてない者がヴァルゴソードに選ばれたのですから。","ENG":"She's the second person in a row who's been chosen by the Virgo Sword from outside the twelve families.","TWN":"因為連續兩次都是完全沒有十二宮血統的人，得到布爾加夫之劍的揀選。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으응? 그렇게 꽉 막힌 아저씨들은 아니지 않았어?","JPN":"ええ？　おじさんたちってそこまで頭の固い人たちだったっけ？","ENG":"What? But I didn't think they were such a narrow-minded lot.","TWN":"嗯？大叔們這麼小心眼喔？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"물론입니다. 단순히 이례적이라고 해서 원로 분들이 전원 불참하실 정도는 아니죠.","JPN":"いえ。単にそういう理由で元老が全員不参加を決めたわけではありません。","ENG":"They're not. At least not enough for all the Elders to not participate in the ceremony.","TWN":"那當然，如果只是單純的違反常例，元老們也不至於全部缺席。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇지 않았다면 전임 기사단장 때도 같은 상황이었을 겁니다.","JPN":"それだけの理由なら、前騎士団長の時もそうしたでしょう。","ENG":"If they were, they would have done the same to the former captain.","TWN":"否則上一任團長的時候，應該也是一樣的情況。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 역시 버고 소드의 선택을 받았을 뿐, 가문과 관련이 없는 사람이었으니까요.","JPN":"彼もまたヴァルゴソードに選ばれただけで、家門とは何の関わりもない人間でしたから。","ENG":"He was also chosen by the Virgo Sword outside the families.","TWN":"他也是受到布爾加夫之劍的揀選而已，但是跟家族完全沒有任何關係。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그러면 왜? 설마 차기 단장이 할배들한테 미운 털 박힐 짓이라도 한 거야?","JPN":"じゃあ何？　次期団長って、元老たちに嫌われるようなことでもしたの？","ENG":"Then, what? Did this new captain do something to earn the geezers' ire?","TWN":"那為什麼？難道下一任的團長，有對那些爺爺們做什麼討人厭的事嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전임 기사단장은 열두 가문과 아무 인연이 없었습니다. <color=#ffd34c>별의 인도자</color>께서 기사단을 세우신 이래 첫 사례였죠.","JPN":"前騎士団長は、12家門と何の縁もありませんでした。<color=#ffd34c>星の導き手</color>が騎士団を立ち上げて以来、初めてのことでした。","ENG":"The former captain had nothing to do with the twelve families, which was unheard of since the <color=#ffd34c>Star Guide</color> established the knights.","TWN":"上一任團長和十二家族完全沒有任何關係，這是<color=#ffd34c>星之引導者</color>創立騎士團以來第一次發生這種事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 그는 레드 시프트가 잃어 버린 <color=#ffd34c>인도자의 무구</color>를 수색하러 떠난 뒤 그대로 종적을 감춰 버렸습니다.","JPN":"しかし彼はレッドシフトが失くした<color=#ffd34c>導く者の武具</color>を捜索に出たきり、姿を消してしまいました。","ENG":"But he disappeared. He went to retrieve the <color=#ffd34c>Guide's Armaments</color> that the Red Shift had lost and never came back.","TWN":"但他去尋找紅移弄丟的<color=#ffd34c>引導者武具</color>後，從此便下落不明。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단장의 상징인 버고 소드를 버려 두고 말입니다.","JPN":"騎士団長の象徴でもある、ヴァルゴソードを置いて。","ENG":"He left behind the Virgo Sword, the symbol of the captain, too.","TWN":"而且還丟掉象徵騎士團團長的布爾加夫之劍。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오오, 그런 일이 있었으면 진즉 말해 주지!","JPN":"へえ、そんなことがあったんだ！　でもなんで話してくれなかったの？","ENG":"Ooh, why didn't you tell me this earlier?","TWN":"喔喔！原來有這種事，你怎麼不早說！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……애초에 리브 경에게 숨긴 적도 없습니다. 듣고 싶은 것만 듣고 살지 마세요.","JPN":"……そもそも、リブ卿に隠してたわけではありません。リブ卿も少しは関心を持ってください。","ENG":"...I've never tried to hide it from you, Dame Liv. Blame your selective hearing.","TWN":"……我從一開始就沒有要瞞著你的意思，你不要只聽你自己想聽的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에스테로사 경은 전임 기사단장의 혈육입니다. 그리고 저 맹세는 전임 기사단장의 것이죠.","JPN":"エステロサ卿は前騎士団長の血筋です。そしてあの誓いは、前騎士団長が言った言葉です。","ENG":"Dame Chevalier is the former captain's kin. And those pledges she's made belonged to him.","TWN":"艾斯特洛索卿是上一任團長的血肉之親，而她剛才說的那段誓詞也是上一任團長的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"진짜? 맘에 안 들면 한 판 붙자는 뜻 아냐?","JPN":"本当に？　ってことは完全に喧嘩売ってるってこと？","ENG":"Really? She's openly challenging anyone who has a problem with that, isn't she?","TWN":"真的嗎？那意思不就是不爽來戰嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"에스테로사 경, 기사단의 규율에 어긋나지 않는 한 어떤 맹세를 할지는 자유지만…….","JPN":"エステロサ卿、騎士団の規律に反しない限りどんな誓いをするかは自由だが……","ENG":"Dame Esterosa, you can pledge anything you want, so long as it doesn't violate the rule of the Knights, but...","TWN":"艾斯特洛索卿，只要在不違反騎士團的規定的前提下，你想說什麼樣的誓詞都可以，但……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아닙니다. 염려해 주셔서 감사합니다.","JPN":"お気遣いありがとうございます。","ENG":"Yes, and thank you for your concern.","TWN":"沒關係，謝謝您替我擔心。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 이것은 전임 기사단장이 저버린 맹세를 완성하겠다는 제 각오입니다.","JPN":"ですが、これは前騎士団長が見捨てた誓いを完遂してみせるという、私の覚悟でもあります。","ENG":"I'm making these pledges to pick up where the former captain has left off.","TWN":"但這段誓詞代表著我的決心，意思就是上一任團長違背的誓詞，會由我來完成。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"……경은 그렇게 생각할지 몰라도, 다른 단원들은 아니야.","JPN":"……だが、他の団員はそう受け入れてはくれないだろう。","ENG":"…I understand what you mean, but the other knights don't.","TWN":"……雖然你是這麼想的，但不代表其他人也這麼想。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"제가 오빠의 뒤를 따르려고 평기사를 지망했을 때, 기사의 정의는 행동으로 펼쳐야 한다고 하셨죠.","JPN":"私が兄の後を継ぐと決めて平騎士を志望した時、騎士の正義は行動で示すべきだと学びました。","ENG":"When I applied for the knight bachelor to follow in my brother's footsteps, you said I must show the justice of the knights through my actions.","TWN":"我跟隨哥哥的腳步報考平民騎士時，哥哥告訴我，騎士的正義是要用行動來展現。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"저는 배운 그대로 실천하는 겁니다.","JPN":"私は学んだとおり行動しているまでです。","ENG":"I'm doing what I've learned.","TWN":"我只是在實踐我所學到的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"허허, 버밍엄 교수께서 처세술은 가르쳐 주시지 않았구먼…….","JPN":"ハハ、バーミンガム教授は卿に世渡りについては教えなかったようだな……","ENG":"Hah hah. Professor Birmingham didn't teach you political skills, did he?","TWN":"呵呵，看來伯明罕教授並沒有教導你待人處事的道理……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그대들의 주인이 이 맹세로 말미암아 짧은 평화를 누릴 수 있길 바라며.","JPN":"そなたたちの主がこの誓いより短い平和を享受できることを祈る。","ENG":"I hope your pledges will bring your masters peace for however long it can.","TWN":"希望你們的主人能因為這個誓詞而享有短暫的和平。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"함께하기를 원하지 않는 자, 앞으로 나와 뜻을 밝혀라.","JPN":"志を共にすることを望まない者は前へ出てその意思を示しなさい。","ENG":"Anyone who doesn't support her pledges, speak now or forever hold your peace.","TWN":"若有人不願意順從的，現在就站出來表達你的意見。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"별을 추종하는 슈레이더의 제프, 저 자의 맹세에 함께할 수 없다.","JPN":"星の追従者、シュレイダーのジェフ。あの者の誓いには賛同できない。","ENG":"I, Jeff of House Schrader that follows the stars, don't support her pledges.","TWN":"跟從星星的舒雷特·傑夫，我無法順從她的誓詞。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"별을 추종하는 카마이클의 데이비드도 마찬가지다!","JPN":"星の追従者、カーマイケルのデイビッドも然り！","ENG":"Neither do I, David of House Carmichael that follows the stars.","TWN":"跟從星星的卡麥特·大衛，我也一樣！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"전임 기사단장이 버고 소드의 결백을 더럽힌 지금, 실력도 인품도 증명되지 않은 자를 어떻게 따르란 말인가!","JPN":"前騎士団長がヴァルゴソードの潔白を汚した今、腕も品性も証明されていない者に従うことはできない！","ENG":"The Virgo Sword's innocence has been left tarnished by the former captain. I can't follow someone who hasn't proven her skill or leadership.","TWN":"上一任團長侮辱了布爾加夫之劍，現在要我們如何能順從像這種能力和人品都沒經過認可的人呢！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"제프 경과 데이비드 경의 말이 옳다!","JPN":"ジェフ卿とデイビッド卿の言うとおりだ！","ENG":"I agree with Sirs Schrader and Carmichael.","TWN":"傑夫卿和大衛卿說的沒錯！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"이런 혼란스러운 시대에 평기사 자격도 제대로 갖추지 못한 자가 단장직에 오르다니!","JPN":"こんな乱世に、平騎士の資格すら満たしていない者が団長になるなんて！","ENG":"I refuse to accept someone who's not even qualified to be a knight bachelor, especially in chaotic times like this.","TWN":"在如此混亂的世代中，一個連平民騎士資格都沒有的人，憑什麼坐上團長之位！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"……이의를 지니지 않은 단원이라고는 이 자리에 리브 경과 피오네 경뿐인 것 같군.","JPN":"……この場で意義を唱えていないのは、リブ卿とフィオネ卿だけのようだ。","ENG":"...Dames Liv and Fione, it seems you're the only ones who have no problem with her pledges.","TWN":"……沒有持反對意見的，似乎只有莉芙卿和菲奧尼卿而已。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"원칙대로라면 맹세를 한 시점부터 경은 이미 단장이지만, 어떤가.","JPN":"原則であれば、誓いを立てた時点で卿は団長となるのだが……どうする？","ENG":"Dame Chevalier, technically, you're captain since you've made your pledges. What say you?","TWN":"根據規定，從你宣示的那一刻開始，你就已經是團長了，你說呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"별의 선택을 받지 않고도 기사단의 정의를 이루기 위해 노력하던 이들입니다.","JPN":"星に選ばれずとも、騎士団の正義を果たすために尽力していた者たちです。","ENG":"Even though they weren't chosen by the stars, they've been helping the Knights achieve justice.","TWN":"雖然他們沒有得到星星的揀選，卻也為實踐騎士正義而努力。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"저는 저들과 함께하고 싶습니다.","JPN":"私は彼らと共に行きたいです。","ENG":"I want to be with them.","TWN":"我想和他們一起努力。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"신념을 지키기 위해 주저없이 나선 용맹한 기사들이여!","JPN":"信念を守るため、恐れず前に出た勇猛たる騎士たちよ！","ENG":"Brave knights, I understand you spoke up to follow your faith.","TWN":"毫不猶豫挺身而出堅守信念的騎士們！"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버고 소드를 뽑아든 자가 단장직을 승계하는 것은 기사단의 오랜 관습이 아닌가!","JPN":"ヴァルゴソードを抜いた者が団長を引き継ぐということは、古くから伝わる騎士団のしきたりではないか！","ENG":"It's our long tradition that whoever draws the Virgo Sword inherits the title of the captain.","TWN":"騎士團自古以來的規矩，能拔出布爾加夫之劍的人就是團長不是嗎！"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그리하여 나는 전임 기사단장이 완수하지 못한 맹세를 다하기 위해 이 자리에 섰다!","JPN":"故に私は、前騎士団長が完遂できなかった誓いを果たすべく、この場に立った！","ENG":"And I stand here to fulfill the pledges that the former captain couldn't.","TWN":"因此我站立在這個位置，就是要完成上一任團長未能完成的誓詞！"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_DAVID","text":{"KOREA":"연고도 없이 기사단에 의탁했던 자들이 버고 소드를 사유물처럼 삼을 셈인가?","JPN":"縁もなく騎士団に頼った者たちが、ヴァルゴソードを私物のように扱うつもりか！","ENG":"The Knights took you orphans under its wing, and now you act as if the Virgo Sword is your personal possession.","TWN":"明明就非親非故的，還硬賴在騎士團，你們是想把布爾加夫之劍據為己有嗎？"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_JEFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_DAVID","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_JEFF","text":{"KOREA":"우리는 인정할 수 없다!","JPN":"私たちは認めない！","ENG":"We refuse to acknowledge you!","TWN":"我們不同意！"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_JEFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_DAVID","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그대들의 불만은 이해한다!","JPN":"君たちが不満に思うのはわかる。","ENG":"I get where you're coming from.","TWN":"我明白你們的不滿！"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"허나 기사가 말하는 정의는 결국 검으로 실현해야 하는 법.","JPN":"しかし、騎士の正義は剣で示すもの。","ENG":"But a knight's justice can only be achieved through their swords.","TWN":"但騎士所說的正義，還是必須用劍來實踐。"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"별의 가호 없이 결투에서 승리한다면, 그대들은 신념을 굽힐 수 있겠는가?","JPN":"星の加護なく決闘で勝利すれば、君たちは信念を曲げてくれるのか？","ENG":"Will you accept me if I win a battle without the Blessing of the Stars?","TWN":"要是我可以在沒有星星的守護下打贏，那你們願意放下歧見嗎？"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_DAVID","text":{"KOREA":"별의 가호를……? 설마 CRF를 사용하지 않고 우릴 상대하겠다는 건가?","JPN":"星の加護なく……？　まさかCRFを使わずに私たちの相手をすると言うのか？","ENG":"Without the Blessing of the Stars? Wait, does she want to fight us without using her CRF?","TWN":"星星的守護……？意思該不會是要在不使用CRF的狀態下和我們對打吧？"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_JEFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_DAVID","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_JEFF","text":{"KOREA":"좋다! 우리에게 패배한다면 단장 취임을 철회하고 버고 소드를 기사단에 봉환해라!","JPN":"いいだろう！　私たちに負ければ就任を撤回し、ヴァルゴソードを騎士団に返せ！","ENG":"Deal! If you lose, we want you to give up your position and return the Virgo Sword to the Knights.","TWN":"很好！要是你輸給我們，就要宣告就任團長一事無效，並且把布爾加夫之劍還給騎士團！"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_JEFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_DAVID","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러지. 하지만 쉽지는 않을 거다.","JPN":"そうしよう。だが、手加減はしない。","ENG":"Deal. But I'm not going to go down so easily.","TWN":"沒問題，只是不太容易。"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그리고는 단장이 슈팡! 파바박! 하고 아저씨들을 순식간에 쓰러뜨린 거 아니겠냐구!","JPN":"それから団長がシュシュッ！　ババババッ！　って、おじさんたちを一瞬で倒したんだよ！","ENG":"And then, BAM! POW! The Captain knocked the guys down!","TWN":"然後團長就咻碰！啪啪啪！三兩下就把大叔們打倒啦！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"평기사 아저씨들이 전부 술렁술렁해서는, 그때부터 모여 있던 전원이랑 쉬지 않고 결투를 하더라니까?","JPN":"平騎士のおじさんたちはみんなざわざわして……そこに集まってた全員と連続で戦ったんだ！","ENG":"The other knight bachelors got so agitated that they all came at her. She fought them all by herself.","TWN":"平民騎士大叔開始騷動，然後團長就和那群人一直打打打，都沒有休息喔！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"손바닥이 부르터서 피가 나는데 조금도 안 흐트러지고 계속 싸웠다구!","JPN":"手のひらが腫れて血が出てるのに、まったく姿勢を乱さずに戦ってたんだ！","ENG":"Her hands started bleeding, but that didn't stop her from fighting them, even harder than before!","TWN":"打到手都起水泡流血了，團長卻一點也沒有亂了陣腳，還是堅持著對戰！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그걸 본 단원들이 단장 앞에 다들 무릎 꿇고 맹세에 따르겠다고 선언한 거야!","JPN":"それを見た団員たちは団長の前に跪いて、団長の誓いに従うって宣言したわけ！","ENG":"Everyone who watched her fight knelt before her and declared their commitment to follow her pledges.","TWN":"看到這一幕的團員，全都來到團長面前屈膝，並且宣示要效忠於誓詞喔！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"역시 단장님……! 굉장하시네요!","JPN":"さすが団長……！　すごいです！","ENG":"Captain! You're so amazing!","TWN":"真不愧是團長……！超厲害！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"상상만 해도 두근두근한 광경이었겠어요.","JPN":"その光景を想像しただけでもドキドキしちゃいます。","ENG":"It must have been so exciting to watch.","TWN":"光是用想的就覺得一定很刺激。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"조금만 더 일찍 움직일 수 있었으면 구경하러 갔을 텐데…….","JPN":"もう少し早く動けるようになっていれば、私も見に行ってたのに……","ENG":"I wish I moved earlier. I would have been there to watch it...","TWN":"要是那時候我的身體可以動的話，我一定會去參觀的……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크흠. 그 때는 나도 모르게 분위기에 조금 취해 있었지.","JPN":"コホン……あの時は私も、あの場の雰囲気に少し酔っていた。","ENG":"Ahem. I might have gotten carried away with that fight.","TWN":"咳咳，那時候我也不自覺地打到有點忘我。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇지만 돌이켜 보면 그 날을 통해 단원들의 뜨거운 열정을 알게 되었다.","JPN":"だが、今思えば……あの出来事のおかげで、団員たちの情熱に気づけたのだと思う。","ENG":"But looking back, I realized I couldn't have understood their passion if they didn't speak up that day.","TWN":"不過現在回想起來，因為那天的事，我才發現到團員們的熱情。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"여러분!","JPN":"皆さん！","ENG":"Everyone!","TWN":"大家！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 부단장. 잠시 리브 경이 옛날 이야기를 꺼내서 다 같이 듣고 있었다.","JPN":"あ、副団長か。リブ卿が昔話をしはじめて、皆で聞いていたところだ。","ENG":"Ah, Deputy. Dame Liv was telling us some old stories.","TWN":"副團長，大家在聽莉芙卿講以前的事。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네. 잠시 자리를 비운 동안 아니나 다를까 일은 팽개치고 놀고 계셨군요.","JPN":"はい。予想通り私がしばらく席を外している間、仕事をほったらかしてサボってたんですね。","ENG":"I see. I left you, just for a moment, and you forgot all about your duties.","TWN":"是的，果然不出我所料，我不在的這段時間，大家都在摸魚。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"가문들이 조달해 주는 활동비는 공금이니 내년도 블루로즈행 크루즈 티켓은 우리 손으로 벌자고 하신 건 단장님입니다.","JPN":"家門から調達してもらっている予算は公金だから、ブルーローズ行きのクルーズ船チケットは私たちの手で稼ごう、と言ったのは団長ですよね？","ENG":"Captain, you're the one who said our money from the families is official funds. We must earn our Blue Rose cruise tickets for the next year on our own.","TWN":"是團長自己說家族分配的活動費是公款，明年藍玫瑰郵輪的船票，要靠我們自己的手去賺。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 지금처럼 다른 단원들과 함께 담소로 시간을 허비하면 되겠습니까? 우리에게 주어진 수영장 청소의 신성한 책무는 어떻게 하실 겁니까?","JPN":"なのに、雑談で時間を無駄にする暇があるのですか？　私たちに与えられた神聖な責務、プール掃除はどうするつもりですか？","ENG":"I can't believe you've been wasting time chitchatting. Did you forget we have an important duty, pool cleaning, to complete?","TWN":"現在有時間在那邊和團員們話當年浪費時間嗎？關於那個神聖的泳池清掃任務，團長打算怎麼辦？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"며, 면목이 없군…….","JPN":"め、面目ない……","ENG":"I-I'm ashamed...","TWN":"我…我真是羞愧……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"앗, 마침 잘 왔어. 부단장.","JPN":"あっ、副団長。ちょうどいいところに。","ENG":"Ah, you came at the right time, Deputy.","TWN":"喔！副團長，你來得正好！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"한솔이랑 에리어스는 모르지? 취임식 날 결투하는 단장을 부단장이 엄청 뜨거운 눈으로 바라보는데…….","JPN":"イチロウとアリウスは知らないよね？　就任式の日、戦う団長を見て副団長が熱い視線を……","ENG":"Hansol, Arius. You probably don't know this, but on the Captain's inauguration day, the Deputy looked at her so intensely...","TWN":"楊瀚和埃里奧斯你們不知道吧？就任儀式那天，副團長一直用超炙熱的眼神，盯著打鬥中的團長欸……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"이크, 나도 그렇게 보네.","JPN":"って、私も熱い視線で見られてるか。","ENG":"Gosh, just like she's looking at me right now.","TWN":"矮額，就是這個眼神！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"어느 입으로 그딴 망발을 뱉는 겁니까, 리브 경! 도망치지 말고 기사답게 맞서십시오!","JPN":"よくもそんな妄言を……！　リブ卿、逃げてないで騎士らしく立ち向かってください！","ENG":"Don't you spread rumors about me, Dame Liv! Stop running and fight me like the knight you are!","TWN":"你在胡說八道什麼？莉芙卿！不要跑！像個騎士出來面對！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장과 리브 경은 체력 단련에 열심이로군.","JPN":"副団長とリブ卿は体力を鍛えるのにに熱心だな。","ENG":"The Deputy and Dame Liv always train so hard.","TWN":"副團長和莉芙卿很認真在鍛鍊體力呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러면 우리도 다시 일을 시작하지. 맡은 일에 최선을 다하지 않으면 기사라 할 수 없어.","JPN":"私たちもそろそろ仕事に戻ろう。任務に最善を尽くしてこそ真の騎士だ。","ENG":"Alright, let's get back to work. True knights do their best in everything they do.","TWN":"那我們也重新開始工作吧！對於受託之事若未盡力完成，就沒資格稱為騎士。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"이것도 훈련의 연속이군요! 알겠습니다, 단장님!","JPN":"これもまた訓練の一環なのですね！　かしこまりました、団長！","ENG":"So, this is an extension of our training. Got it, Captain!","TWN":"這也是訓練的一環嗎？遵命，團長！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"열심히 일해서 다 같이 블루로즈로 가요~","JPN":"みんなで頑張ってブルーローズに行きましょう～","ENG":"Let's work hard and go to Blue Rose together!","TWN":"一起努力工作來去藍玫瑰～"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};